@ARTICLE{10.1016/j.anl.2025.12.006,
	author = {Honda, N. and Watanabe, Y. and Komazawa, D. and Hirosaki, M. and Sone, M.},
	title = {Three-dimensional analysis of vocal fold nodules in operatic soprano singers undergoing microlaryngeal surgery: Differences according to voice type subcategories (Lyric vs. Dramatic)},
	journal = {Auris Nasus Larynx},
	year = {2026},
	abstract = {Objectives Vocal demands in opera singers vary not only by vocal range but also by voice type subcategories (e.g., lyric vs. dramatic), which shapes technique and repertoire. Despite this, little is known about how these voice subcategories influence vocal fold pathology. To address this gap, we investigate the three-dimensional characteristics of vocal fold nodules in professional soprano opera singers and to clarify morphological differences based on voice type subcategories (lyric vs. dramatic). Methods This retrospective study included 19 professional soprano singers who underwent microlaryngeal surgery for bilateral vocal fold nodules between January 2018 and May 2023. Voice type subcategories, based on self-reported repertoire, was categorized as either lyric or dramatic. Nodules were classified as edematous or fibrous. Vertical location, estimated area, estimated contact area, and estimated volume of the nodules were calculated using intraoperative measurements and surgical video review. Statistical comparisons were performed between the lyric and dramatic groups. Results A total of 38 nodules were analyzed: 26 from lyric sopranos and 12 from dramatic sopranos. Lyric sopranos predominantly exhibited edematous nodules (24/26), while dramatic sopranos had a higher proportion of fibrous nodules (6/12). In both groups, nodules were more frequently located in the upper part of the vocal folds. Lyric sopranos showed significantly greater width, estimated area, estimated contact area, and estimated volume of vocal fold nodules compared to dramatic sopranos. Conclusion Voice-type subcategories may influence the morphological characteristics of vocal fold nodules in professional soprano singers. Lyric sopranos tend to develop larger, edematous nodules, likely due to repetitive high-frequency phonation, while dramatic sopranos are more prone to smaller, fibrotic nodules, potentially resulting from greater horizontal mechanical stress. Copyright © 2025. Published by Elsevier B.V. ER -},
	doi = {10.1016/j.anl.2025.12.006},
	type = {JOUR}
}

@ARTICLE{10.31862/2309-1428-2021-9-3-107-121,
	author = {Korchagina, N.V. and Polyakova, А.A.},
	title = {Content and Main Directions of Training Singers for the Professional Performance Activity of the Artist-Vocalist of Musical},
	journal = {Musical Art and Education},
	year = {2021},
	abstract = {The article is devoted to identifying the features of the work and professional training of an artist-vocalist of a musical, one of the most relevant and demanded genres of the 21st century. It is shown that the formation of the musical as a synthetic genre was carried out under the influence of musical theater, opera, operetta, vaudeville, minstrel show, burlesque. The formation of such varieties as American, British, French and Russian musicals was due to the specifics of national composing schools, approaches to the choice of the plot, the interpretation of drama and forms of theatrical practice. The idea is substantiated that the versatility of the genre imposes a number of special requirements on actors. For a deeper and more multifaceted understanding of the activities of an artist-vocalist of a modern musical, his Professiogram is offered. It contains a general description of the content of the singer’s work (functions, responsibilities and tasks), and also includes an analysis of the requirements for professional knowledge, skills, business and personal qualities of the performer. To concretize the main directions of professional training of an artist-vocalist of a musical, the article also considers the key components of his performing activity. These are vocal, acting, choreographic work and work on the stage image. In the article conclusion, it is concluded that drawing up a professiogram allows to identify professional requirements for an individual educational training strategy, to improve artistic skills and the formation of specialized educational programs in educational institutions of the corresponding profile and level, including in the system of additional music education. © 2021. All Rights Reserved. ER -},
	doi = {10.31862/2309-1428-2021-9-3-107-121},
	type = {JOUR}
}

@ARTICLE{10.1525/ncm.2024.48.1-2.19,
	author = {Sabbatini, T.},
	title = {Louise: Wagnerism, Realism, Stage, Screen},
	journal = {Nineteenth Century Music},
	year = {2024},
	abstract = {Gustave Charpentier’s opera Louise (1900) strikes an unlikely but successful compromise between a Wagnerian aesthetic and a Naturalist one. The opera’s very musical language adopts Wagnerian leitmotivic technique, but eschews the Wagnerian tendency toward the autonomy of the artwork, and instead references both other compositions and the external world. This tension is exploited in Abel Gance’s 1939 film adaptation of Louise. Gance’s Louise conflates Charpentier’s male protagonist with Charpentier himself, and reenacts the opera’s plot and the opera’s genesis at the same time. It is, therefore, a hybrid between two types of early opera film, the “prose opera” and the “parallel opera.” Musically, Charpentier’s score is disassembled and reassigned to the various components of the film’s soundtrack: underscoring, diegetic music, “artless” singing, sound effects. The opera’s music, then, becomes the material through which Gance builds a work that is thoroughly conceived for the new medium. And in the context of the new medium, the tension between Wagnerism and Naturalism is replaced by a tension between a photographic mode (the relatively unmediated depiction of reality) and an auratic mode (reality as filtered through the imagination of the character-composer). © 2024 by The Regents of the University of California. All rights reserved. ER -},
	doi = {10.1525/ncm.2024.48.1-2.19},
	type = {JOUR}
}

@ARTICLE{10.31862/2309-1428-2024-12-2-126-136,
	author = {Semkin, D.N.},
	title = {THE LAWS OF SUCCESSFUL PROFESSIONAL ACTIVITY OF AN ACADEMIC SINGER},
	journal = {Musical Art and Education},
	year = {2024},
	abstract = {The article briefly describes the features of vocal pedagogy and methodology as a combination of the empirical basis and scientific basis of the singing process, and outlines the need to develop understandable rules (laws) for the successful training and professional work of academic singers. For the first time, a classification of the laws of the singing process has been proposed, including the laws of physics, acoustics, physiology and psychology, as well as the patterns of life of an academic singer. These laws will be useful not only for academic vocal teachers, but also for singers in the implementation of their long and successful professional career. © Семкин Д. Н. ER -},
	doi = {10.31862/2309-1428-2024-12-2-126-136},
	type = {JOUR}
}

@ARTICLE{10.1093/llc/fqad074,
	author = {Tian, R. and Yin, R. and Ban, J.},
	title = {Research on character tone trend clustering of Kunqu Opera based on quantum adaptive genetic algorithm},
	journal = {Digital Scholarship in the Humanities},
	year = {2024},
	abstract = {Kunqu, one of the oldest forms of Chinese opera, features a unique artistic expression arising from the interplay between vocal melody and the tonal quality of its lyrics. Identifying Kunqu's character tone trend (vocal melodies derived from tonal quality of the lyrics) is critical to understanding and preserving this art form. Traditional research methods, which rely on qualitative descriptions by musicologists, have often been debated due to their subjective nature. In this study, we present a novel approach to analyze the character tone trend in Kunqu by employing computer modeling machine learning techniques. By extracting the character tone trend of Kunqu using computational modeling methods and employing machine learning techniques to apply cluster analysis on Kunqu's character tone melody, our model uncovers musical structural patterns between singing and speech, validating and refining the qualitative findings of musicologists. Furthermore, our model can automatically assess whether a piece adheres to the rhythmic norms of 'the integration of literature and music' in Kunqu, thus contributing to the digitization, creation, and preservation of this important cultural heritage. © The Author(s) 2023. ER -},
	doi = {10.1093/llc/fqad074},
	type = {JOUR}
}

@ARTICLE{10.3390/jfmk7020036,
	author = {Corsi, M. and Orlandi, G. and Bini, V. and Stefani, L.},
	title = {Integrated Sports Medicine: A First Investigation of Heart Performance in Opera Singers},
	journal = {Journal of Functional Morphology and Kinesiology},
	year = {2022},
	abstract = {Introduction: Opera singers are continuously subjected to cardiopulmonary exercise. The impact on cardiac performance has not been studied. Our aim was to verify the impact of singing on heart performance, particularly by the evaluation of ECG and deformation parameters as strain, rotation and twist. Methods: A population of 17 OS (opera singers) underwent a 12-lead ECG and 2D echocardiographic evaluation. A post-processing analysis of the images to obtain the deformation parameters was included. The data expressed as mean as SD were compared to a group of 15 high-level athletes (A). Results: In both groups, the ECG parameters, 2D standard systodiastolic parameters and pulmonary pressure were normal, and in the OS group—LVDd: 47 ± 2.75 mm, LVSd: 31 ± 3.38 mm, E/A: 1.08 ± 0.23, RV: 27.63 ± 3.38 mm; in the A group—LVDd: 51 ± 1.50 mm, LVSd: 32 ± 2.50 mm, E/A: 2.37 ± 0.73, RV: 25.00 ± 3.00 mm. Indexed LV mass was significantly greater in athletes, while ejection fraction (EF) results were higher in OS. Deformation parameters did not differ among the two groups, with the exclusion of GLS expressing a major value in athletes. Rotational parameters resulted in the OS group similar to the athletes. Conclusions: OS show myocardial performance as high as the athletes. The data obtained suggest a positive impact of regular training as an opera singer. Deformation parameters highlight the fitness status in this group with a specific remodeling in RV in the presence of normal PP. Classic music singing appears to have a training effect on the heart. Further studies are necessary to confirm this hypothesis. © 2022 by the authors. Licensee MDPI, Basel, Switzerland. ER -},
	doi = {10.3390/jfmk7020036},
	type = {JOUR}
}

@ARTICLE{10.19108/koers.89.1.2589,
	author = {Olivier, A.},
	title = {Emma Renzi: From opera singer to singing pedagogue: A philosophical perspective},
	journal = {Koers},
	year = {2024},
	abstract = {In one sense, this article is an autobiography about Emma Renzi, who turned 97 on 8 April 2023. Renzi was an internationally celebrated South African opera singer who was also a pedagogue and a role model for many singers during the second phase of her illustrious career. The transition from singer to exceptionally gifted pedagogue was a conscious decision that she made to express her convictions that she should live her life and her talents in the most positive and focused way. It is thus this odyssey that is investigated and analysed in this article. Due to the nature of our bond, the discussions in this article focus on Renzi’s professional career, her memories of a specific era, the technical aspects of singing instruction, and the challenges of a professional singing career. The wealth of Renzi’s first-hand experiences and her knowledge of styles in various singing genres are invaluable for the development of young singers and instructors. It is also of historical importance for South Africans to honour the legacy of a singer who achieved international fame during her career and made it her life’s mission to pass on the insights she gained to her students. In this way, she shaped them with professionalism, compassion, and understanding, enabling them to pursue illustrious and fulfilling careers of their own. Autobiographical research includes narratives as well as the views of other authorities about lived experiences and their significance for singers and singing pedagogues. In this study, it was possible to lead and shape students and not merely teach them. A framework for the article was constructed by describing special experiences and challenges. Problems, life conditions and the informal interaction between Renzi and the audience, conductors, co-singers, agents, and students are highlighted. Ultimately, the meaning of Renzi’s career is underlined for South Africans. Her lived experiences as an international singer and renowned pedagogue offer a valuable background for singers and teachers to help singers realise their full human capacity. © 2024. The Author(s). Published under the Creative Commons Attribution License. ER -},
	doi = {10.19108/koers.89.1.2589},
	type = {JOUR}
}

@ARTICLE{10.5216/mh.v22.73226,
	author = {Xia, W.},
	title = {Peculiarities of Singing in Chinese Popular and Traditional Music: Influence of Musical Genres on Vocals},
	journal = {Musica Hodie},
	year = {2022},
	abstract = {Under the conditions of multiculturalism, Chinese vocal art has formed its own unique theoretical system based on the characteristics of vocalization, articulation, diction, and breathing. The aims of the study are to identify singing features in Chinese popular and traditional music, as well as to determine the ways in which musical genres influence vocals. Two teachers of modern vocal, two teachers of traditional vocal, 30 students of the Vocal Arts Department of Beijing University, art historians from the Central Conservatory of Music and Lishui University took part in the study. According to the study purpose, it was found that in traditional Chinese vocal arts, the main technique is falsetto (58%), mixed techniques (21.2%), vibrato (13.2%), overtone singing (6.1%), and glissando (1.5%) are also used. In popular singing the key technique is splitting (33.6%), also used: subtone (20.2%), vibrato (17.7%), drive (12.1%), glissando (11.1%), vocal fry register (9.2%), falsetto (3.3%), overtone singing (2%). As a result of the correlation analysis the dependence of popular singing techniques on traditional singing was determined. The coefficient of determination was 33.5%. It was also determined that when performing pop music, vibrato is controlled; noises and growling tones are used in rock music; uncontrolled vibrato, falsetto, and mixed techniques are used in opera; nasal sounds and minimal vibrato are in folk/country music; clear diction, articulation, slides, and scatting in blues/jazz; rhythmic and nasal sounds in hip-hop. The experiment results can be used in pedagogy for teaching vocals in China and abroad, as part of cultural activities related to the organization of events such as festivals, concerts, tourist programs, theatrical performances, etc. © 2022 Universidade Federal de Goias. All rights reserved. ER -},
	doi = {10.5216/mh.v22.73226},
	type = {JOUR}
}

@ARTICLE{10.3389/fpsyg.2025.1568982,
	author = {Kondo, H. and Kondoh, S. and Fujii, S.},
	title = {Perceived vibrato and the singing power ratio explain overall evaluations in opera singing},
	journal = {Frontiers in Psychology},
	year = {2025},
	abstract = {In opera singing competitions, judges use an overall score to evaluate the singers' voices and determine their rankings. This score not only guides the singers' technique and expressiveness but also serves as a crucial indicator that can significantly influence their careers. However, the specific elements captured by this overall score remain unclear. To address this gap, the present study analyzed opera singing recordings to identify the factors that explain the overall score. Ten trained female Japanese singers performed “Caro mio ben” under standardized recording conditions. Four experts evaluated the recorded performances by assigning an overall score of 100 points and rating six vocal attributes: vibrato, resonance, timbre, diction, intonation, and expressiveness. The recordings were then analyzed to calculate specific acoustic and audio features, including the singing power ratio (SPR), harmonic-to-noise ratio (HNR), and loudness units full scale (LUFS). We developed two linear mixed models: the first regressed the overall score on the subjective vocal attributes, whereas the second predicted the overall score from the acoustic features. Evaluator identity was included as a random effect in both models. The results showed that vibrato was a significant predictor of the overall score in the first model. In the second model, only SPR emerged as a significant predictor. These findings suggest that vibrato, which reflects emotional expressiveness and vocal control, and SPR, which indicates the relative power in the high-frequency band (2–4 kHz) and assists a voice clearer than the accompaniment, are key factors in explaining the overall score in opera singing. Copyright © 2025 Kondo, Kondoh and Fujii. ER -},
	doi = {10.3389/fpsyg.2025.1568982},
	type = {JOUR}
}

@ARTICLE{10.5281/zenodo.18231635,
	author = {Ma, M. and Wang, S.-W.},
	title = {DESIGN AND IMPLEMENTATION OF A DIGITAL MODULE ON IMPERIAL CHINESE THEATRE FOR PRE-SERVICE MUSIC TEACHERS: FOCUSING ON KUNQU MELODIC PATTERNS AND VOCAL EXPRESSION},
	journal = {Scientific Culture},
	year = {2025},
	abstract = {Imperial Chinese theatre, especially Kunqu opera, has huge cultural and pedagogical importance in the field of music education. Although Kunqu is a recognized example of Intangible Cultural Heritage of the UNESCO, it is still underrepresented in the present-day music teacher training curricula. The presence of a gap in the existing literature in digital pedagogical materials specifically designed to meet the needs of pre-service music educators, has been identified. This research fills this gap through the design and execution of a web-based learning module that would be devoted to melodic patterns of Kunqu and the expression of vocal directed to pre-service music teachers in particular. The study utilized a systematic literature review (SLR) as its main methodological approach and synthesized 16 research papers on music pedagogy, digital education, and Chinese opera studies. The results served as the basis of creating an interactive and multimedia-based module, which combines historical background, audio-visual analysis, and instructed vocal practice. The major insights are that exposure to Kunqu online adds to the appreciation of learners, their technical knowledge, and their confidence when working with non-Western vocal culture. Intercultural awareness and pedagogical creativity in music teaching are also encouraged in the module. The findings highlight the possibility of digital tools in filling the cultural content divide of teacher education. The research will be relevant to the development of the curriculum as well as to the discussion on the integration of traditional performing arts into the music education of the 21st century. © 2025. ER -},
	doi = {10.5281/zenodo.18231635},
	type = {JOUR}
}
